import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { AppScreen, Platform } from './types';
import Header from './components/Header';
import WelcomeScreen from './components/WelcomeScreen';
import MainSelectionScreen from './components/MainSelectionScreen';
import ProductOptionsScreen from './components/ProductOptionsScreen';
import NovaVariantSelector from './components/NovaVariantSelector';
import MJVariantSelector from './components/MJVariantSelector';

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>(AppScreen.WELCOME);
  const [selectedPlatform, setSelectedPlatform] = useState<Platform | null>(null);

  const navigateTo = (screen: AppScreen) => {
    setCurrentScreen(screen);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePlatformSelect = (platform: Platform) => {
    setSelectedPlatform(platform);
    if (platform === Platform.ANDROID) {
      navigateTo(AppScreen.ANDROID_VARIANTS);
    } else if (platform === Platform.SPECIAL_OFFER) {
      navigateTo(AppScreen.SPECIAL_OFFER);
    } else {
      navigateTo(AppScreen.PRODUCT_OPTIONS);
    }
  };

  return (
    <div className="min-h-screen font-exo text-text-primary selection:bg-primary selection:text-surface">
      <Header currentScreen={currentScreen} onNavigate={navigateTo} />

      <main className="container mx-auto px-4 py-20 relative z-10">
        {currentScreen === AppScreen.WELCOME && (
          <WelcomeScreen onContinue={() => navigateTo(AppScreen.MAIN_SELECTION)} />
        )}

        {currentScreen === AppScreen.MAIN_SELECTION && (
          <MainSelectionScreen onPlatformSelect={handlePlatformSelect} />
        )}

        {currentScreen === AppScreen.PRODUCT_OPTIONS && (
          <ProductOptionsScreen 
            platform={selectedPlatform} 
            onBack={() => navigateTo(AppScreen.MAIN_SELECTION)}
            onSelectOption={(option) => {
              if (option === 'windows-app') {
                navigateTo(selectedPlatform === Platform.NOVA ? AppScreen.NOVA_VARIANTS : AppScreen.MJ_VARIANTS);
              } else if (option === 'custom-name') {
                navigateTo(AppScreen.CUSTOM_NAME);
              }
            }}
          />
        )}

        {currentScreen === AppScreen.NOVA_VARIANTS && (
          <NovaVariantSelector 
            onBack={() => navigateTo(AppScreen.PRODUCT_OPTIONS)} 
            onSelect={(variant) => console.log('Selected variant:', variant)}
          />
        )}

        {currentScreen === AppScreen.MJ_VARIANTS && (
          <MJVariantSelector 
            onBack={() => navigateTo(AppScreen.PRODUCT_OPTIONS)}
            onSelect={(variant) => console.log('Selected variant:', variant)}
          />
        )}
      </main>

      {/* Footer / Notification area could go here */}
    </div>
  );
};

export default App;

