import React, { useState, useEffect } from 'react';

interface MJVariantSelectorProps {
  onBack: () => void;
  onSelect: (variant: string) => void;
}

const MJVariantSelector: React.FC<MJVariantSelectorProps> = ({ onBack, onSelect }) => {
  const [timeLeft, setTimeLeft] = useState({ days: 0, hours: 0, minutes: 0, seconds: 0 });

  useEffect(() => {
    const targetDate = new Date('January 1, 2026 00:00:00').getTime();
    const interval = setInterval(() => {
      const distance = targetDate - new Date().getTime();
      if (distance < 0) {
        clearInterval(interval);
        return;
      }
      setTimeLeft({
        days: Math.floor(distance / (1000 * 60 * 60 * 24)),
        hours: Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        minutes: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        seconds: Math.floor((distance % (1000 * 60)) / 1000)
      });
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="animate-in slide-in-from-right duration-500">
      <button 
        onClick={onBack}
        className="mb-8 flex items-center text-text-secondary hover:text-primary transition-colors font-orbitron text-xs font-bold tracking-widest"
      >
        <i className="fas fa-arrow-left mr-2"></i> BACK
      </button>

      <div className="max-w-3xl mx-auto text-center mb-12">
        <h2 className="font-orbitron text-3xl md:text-4xl font-bold mb-4">MJ v1 - <span className="text-secondary">Emotional Intelligence</span></h2>
        <p className="text-text-secondary">Your empathetic AI companion for Windows. Redefining human-machine interaction.</p>

        <div className="mt-8 bg-secondary/10 p-6 rounded-3xl border border-secondary/30 max-w-xl mx-auto">
          <div className="text-secondary font-orbitron text-sm font-bold tracking-widest mb-4 flex items-center justify-center">
            <i className="fas fa-gift mr-2"></i> NEW YEAR SPECIAL LAUNCH
          </div>
          <div className="grid grid-cols-4 gap-4 font-orbitron">
            <div className="bg-surface p-3 rounded-xl border border-white/5">
              <div className="text-2xl font-bold text-white">{String(timeLeft.days).padStart(2, '0')}</div>
              <div className="text-[8px] text-text-secondary uppercase">Days</div>
            </div>
            <div className="bg-surface p-3 rounded-xl border border-white/5">
              <div className="text-2xl font-bold text-white">{String(timeLeft.hours).padStart(2, '0')}</div>
              <div className="text-[8px] text-text-secondary uppercase">Hours</div>
            </div>
            <div className="bg-surface p-3 rounded-xl border border-white/5">
              <div className="text-2xl font-bold text-white">{String(timeLeft.minutes).padStart(2, '0')}</div>
              <div className="text-[8px] text-text-secondary uppercase">Mins</div>
            </div>
            <div className="bg-surface p-3 rounded-xl border border-white/5">
              <div className="text-2xl font-bold text-white">{String(timeLeft.seconds).padStart(2, '0')}</div>
              <div className="text-[8px] text-text-secondary uppercase">Secs</div>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-xl mx-auto">
        <div className="glass-card p-8 rounded-3xl relative overflow-hidden group">
          <div className="absolute -top-10 -right-10 w-40 h-40 bg-secondary/20 rounded-full blur-3xl group-hover:bg-secondary/40 transition-all"></div>

          <div className="flex items-center justify-between mb-8">
            <div className="w-16 h-16 bg-secondary/20 rounded-2xl flex items-center justify-center">
              <i className="fas fa-heart text-secondary text-3xl animate-pulse"></i>
            </div>
            <div className="text-right">
              <div className="text-3xl font-orbitron font-black text-white">₹1299</div>
              <div className="text-[10px] text-secondary font-bold uppercase tracking-widest">Special Launch Price</div>
            </div>
          </div>

          <h3 className="font-orbitron font-bold text-2xl mb-6">MJ v1 - Empathy Pack</h3>

          <ul className="space-y-4 mb-10">
            {[
              'Emotionally intelligent conversations',
              'Empathy-based response system',
              'Human-like emotional understanding',
              'Mood detection & adaptation',
              'Therapeutic conversation support',
              'Windows desktop integration'
            ].map((f, i) => (
              <li key={i} className="flex items-start text-sm text-text-secondary">
                <i className="fas fa-heart text-secondary mt-1 mr-3 text-xs"></i>
                <span>{f}</span>
              </li>
            ))}
          </ul>

          <div className="bg-white/5 p-6 rounded-2xl border border-white/10 mb-8">
            <label className="text-[10px] font-bold text-text-secondary uppercase tracking-[0.2em] mb-3 block">Redeem Code</label>
            <div className="flex gap-3">
              <input 
                type="text" 
