        {isOpen && (
          <div className="lg:hidden pb-4 space-y-2 animate-in slide-in-from-top duration-300">
            {navItems.map((item) => (
              <button
                key={item.label}
                onClick={() => {
                  onNavigate(item.screen);
                  setIsOpen(false);
                }}
                className="flex items-center space-x-4 w-full p-3 text-left hover:bg-white/5 rounded-lg transition-colors"
                style={{ color: currentScreen === item.screen ? themeColor : 'white' }}
              >
                <i className={`fas ${item.icon} w-5`} style={{ color: themeColor }}></i>
                <span className="uppercase text-xs font-bold tracking-widest">{item.label}</span>
              </button>
            ))}
          </div>
        )}
      </div>
    </nav>
  );
};

