import React, { useState, useEffect } from 'react';
import { Platform } from '../types';

interface MainSelectionScreenProps {
  onPlatformSelect: (platform: Platform) => void;
}

const MainSelectionScreen: React.FC<MainSelectionScreenProps> = ({ onPlatformSelect }) => {
  const targetDate = new Date('2025-01-20T00:00:00').getTime();
  const [timeLeft, setTimeLeft] = useState(targetDate - Date.now());
  const isLocked = timeLeft > 0;

  useEffect(() => {
    if (!isLocked) return;

    const timer = setInterval(() => {
      const remaining = targetDate - Date.now();
      if (remaining <= 0) {
        setTimeLeft(0);
        clearInterval(timer);
      } else {
        setTimeLeft(remaining);
      }
    }, 1000);

    return () => clearInterval(timer);
  }, [isLocked, targetDate]);

  const formatTime = (ms: number) => {
    const days = Math.floor(ms / (1000 * 60 * 60 * 24));
    const hours = Math.floor((ms % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    const minutes = Math.floor((ms % (1000 * 60 * 60)) / (1000 * 60));
    const seconds = Math.floor((ms % (1000 * 60)) / 1000);
    return `${days}d ${hours}h ${minutes}m ${seconds}s`;
  };

  return (
    <div className="animate-in slide-in-from-bottom duration-600 px-2">
      <div className="text-center mb-10 md:mb-16">
        <h2 className="font-orbitron text-3xl md:text-6xl text-white font-black tracking-tighter mb-4 leading-none">
